import fs from "node:fs";
import path from "node:path";
function ensureWritesEnabled(config) {
    if (!config.allowRuntimeWrites) {
        throw new Error("Runtime writes are disabled. Enable allowRuntimeWrites in plugin config before authoring operations that create files.");
    }
}
function writeJsonArtifact(folder, id, payload) {
    fs.mkdirSync(folder, { recursive: true });
    const outputPath = path.join(folder, `${id}.json`);
    fs.writeFileSync(outputPath, JSON.stringify(payload, null, 2) + "\n", "utf8");
    return { outputPath };
}
export function createMoltBlock(paths, config, params) {
    ensureWritesEnabled(config);
    const folder = params.targetFolder
        ? path.resolve(params.targetFolder)
        : path.join(paths.resleeverBlocksDir, "generated", "molt", params.moltType);
    const payload = {
        id: params.id,
        title: params.title,
        kind: "molt-block",
        moltType: params.moltType,
        summary: params.summary,
        authority: params.authority ?? 50,
        tags: params.tags ?? [],
        createdBy: "openclaw-umg-envoy-agent",
        createdAt: new Date().toISOString()
    };
    return writeJsonArtifact(folder, params.id, payload);
}
